        // The regex [a-z]+(?:-[a-z]+)* inherently ensures:
        // 1. Starts with [a-z]
        // 2. Any subsequent '-' must be followed by [a-z]+
        // Therefore, the matches from this regex are precisely the valid, maximal words.

        rawWords.push(potentialWord);
    }

